import React from 'react';
import './Sidebar.css';

interface SidebarProps {
  currentPage?: string;
  onPageChange?: (page: string) => void;
}

const Sidebar: React.FC<SidebarProps> = ({ currentPage = 'Dashboard', onPageChange }) => {
  const handleMenuClick = (page: string) => {
    if (onPageChange) {
      onPageChange(page);
    }
  };

  return (
    <div className="sidebar">
      <div className="sidebar-header">
        <div className="logo">
          <div className="logo-icon">
            <img src="/Frame 2 1 (1).svg" alt="MelloMinds" />
          </div>
        </div>
      </div>

      <div className="sidebar-content">
        <div className="menu-section">
          <div className="menu-label">MENU</div>
          <nav className="menu-nav">
            <div 
              className={`menu-item ${currentPage === 'Dashboard' ? 'active' : ''}`}
              onClick={() => handleMenuClick('Dashboard')}
            >
              <img src="/Light-Icon/Iconly/Light-Outline/Category.svg" alt="Dashboard" className="menu-icon" />
              <span>Dashboard</span>
            </div>
            <div 
              className={`menu-item ${currentPage === 'All Users' ? 'active' : ''}`}
              onClick={() => handleMenuClick('All Users')}
            >
              <img src="/Light-Icon/Iconly/Light-Outline/Profile.svg" alt="All Users" className="menu-icon" />
              <span>All Users</span>
            </div>
            <div className="menu-item">
              <img src="/Light-Icon/Iconly/Light-Outline/Chart.svg" alt="Analytics" className="menu-icon" />
              <span>Analytics</span>
            </div>
            <div className="menu-item">
              <img src="/Light-Icon/Iconly/Light-Outline/Wallet.svg" alt="Payments" className="menu-icon" />
              <span>Payments</span>
            </div>
          </nav>
        </div>

        <div className="menu-section">
          <div className="menu-label">GENERAL</div>
          <nav className="menu-nav">
            <div className="menu-item">
              <img src="/Light-Icon/Iconly/Light-Outline/Logout.svg" alt="Logout" className="menu-icon" />
              <span>Logout</span>
            </div>
          </nav>
        </div>
      </div>

      <div className="demo-mode-section">
        <button className="demo-mode-btn">
          <img src="/Light-Icon/Iconly/Light-Outline/Play.svg" alt="Demo" className="demo-icon" />
          <span>Demo Mode</span>
        </button>
      </div>
    </div>
  );
};

export default Sidebar;
